import React from 'react';
import { Card } from './Card';
import s from './Days.module.scss';

interface Props {
  
}
export interface Day {
    day: string;
    day_info: string;
    icon_id: string;
    temp_day: string;
    temp_night: string;
    info: string;
  }

export const Days = (props: Props) => {
    const days: Day[] = [
        {
          day: 'Сегодня',
          day_info: '22 апр',
          icon_id: 'sun',
          temp_day: '+25',
          temp_night: '+11',
          info: 'Солнечно',
        },
        {
          day: 'Завтра',
          day_info: '23 апр',
          icon_id: 'small_rain_sun',
          temp_day: '+18',
          temp_night: '+4',
          info: 'небольшой дождь и солнце',
        },
        {
          day: 'Ср',
          day_info: '24 апр',
          icon_id: 'small_rain',
          temp_day: '+18',
          temp_night: '+5',
          info: 'небольшой дождь',
        },
        {
          day: 'Чт',
          day_info: '25 апр',
          icon_id: 'mainly_cloudy',
          temp_day: '+18',
          temp_night: '+3',
          info: 'Облачно',
        },
        {
          day: 'Пт',
          day_info: '26 апр',
          icon_id: 'rain',
          temp_day: '+18',
          temp_night: '+2',
          info: 'Облачно',
        },
        {
          day: 'Сб',
          day_info: '27 апр',
          icon_id: 'sun',
          temp_day: '+18',
          temp_night: '+4',
          info: 'Облачно',
        },
        {
          day: 'Вс',
          day_info: '28 апр',
          icon_id: 'sun',
          temp_day: '+18',
          temp_night: '+15',
          info: 'Облачно',
        },
      ];
    return (
  <div className={s.days}>
      {days.map((day: Day) => (
          <Card day={day} key={day.day} />
        ))}

  </div>
  );
};
